<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Ubuntu Desktop</title>
<style>
  * { margin: 0; padding: 0; box-sizing: border-box; }

  body {
    overflow: hidden;
    font-family: 'Ubuntu', 'Segoe UI', Arial, sans-serif;
    background: #1a1a2e;
    height: 100vh;
    width: 100vw;
  }

  /* Desktop wallpaper area */
  #desktop {
    position: relative;
    width: 100%;
    height: calc(100% - 48px);
    background: linear-gradient(135deg, #1a2a6c, #b21f1f, #fdbb2d);
    background-size: 400% 400%;
    animation: gradientShift 15s ease infinite;
    overflow: hidden;
  }

  @keyframes gradientShift {
    0% { background-position: 0% 50%; }
    50% { background-position: 100% 50%; }
    100% { background-position: 0% 50%; }
  }

  /* Desktop icons */
  .desktop-icon {
    position: absolute;
    top: 20px;
    left: 20px;
    width: 80px;
    text-align: center;
    color: white;
    cursor: pointer;
    user-select: none;
    padding: 5px;
    border-radius: 4px;
    transition: background 0.15s;
    z-index: 1;
  }

  .desktop-icon:hover { background: rgba(255,255,255,0.15); }

  .desktop-icon .icon-preview {
    width: 48px;
    height: 48px;
    margin: 0 auto 6px;
    border-radius: 8px;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 24px;
  }

  .desktop-icon .icon-label {
    font-size: 13px;
    text-shadow: 0 1px 3px rgba(0,0,0,0.8);
  }

  /* Taskbar */
  #taskbar {
    position: fixed;
    bottom: 0;
    left: 0;
    right: 0;
    height: 48px;
    background: rgba(30, 30, 50, 0.92);
    backdrop-filter: blur(12px);
    display: flex;
    align-items: center;
    padding: 0 8px;
    z-index: 9999;
    border-top: 1px solid rgba(255,255,255,0.08);
  }

  #taskbar .spacer { flex: 1; }

  /* Launcher buttons */
  #open-files, #open-notepad {
    display: flex;
    align-items: center;
    gap: 6px;
    padding: 6px 14px;
    border-radius: 8px;
    cursor: pointer;
    font-size: 13px;
    color: #e0e0e0;
    background: rgba(255,255,255,0.06);
    border: none;
    transition: all 0.15s ease;
    user-select: none;
    white-space: nowrap;
  }

  #open-files:hover, #open-notepad:hover {
    background: rgba(255,255,255,0.14);
    color: white;
  }

  #open-files .icon, #open-notepad .icon { font-size: 18px; }

  /* Window */
  .window {
    position: absolute;
    top: 60px;
    left: 50%;
    transform: translateX(-50%);
    width: 720px;
    min-height: 380px;
    max-height: calc(100vh - 140px);
    background: #2d2d44;
    border-radius: 10px;
    box-shadow: 0 8px 32px rgba(0,0,0,0.5), 0 2px 8px rgba(0,0,0,0.3);
    display: none;
    flex-direction: column;
    overflow: hidden;
    border: 1px solid rgba(255,255,255,0.06);
    z-index: 100;
  }

  .window.active { display: flex; z-index: 200; }

  /* Window title bar */
  .win-titlebar {
    height: 38px;
    background: #1e1e32;
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 0 12px;
    cursor: default;
    user-select: none;
    border-bottom: 1px solid rgba(255,255,255,0.04);
  }

  .win-title {
    font-size: 13px;
    color: #c8c8d8;
    flex: 1;
    text-align: center;
    pointer-events: none;
  }

  .win-controls { display: flex; gap: 6px; }

  .win-close {
    width: 24px;
    height: 24px;
    border-radius: 50%;
    background: transparent;
    border: none;
    color: #999;
    font-size: 16px;
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: center;
    transition: all 0.15s;
    line-height: 1;
  }

  .win-close:hover { background: #e95757; color: white; }

  /* Window content */
  .win-body { flex: 1; overflow: hidden; position: relative; }

  /* Files app styles */
  #files-window .win-body { display: flex; flex-direction: column; }

  .file-toolbar {
    padding: 8px 12px;
    background: #25253a;
    border-bottom: 1px solid rgba(255,255,255,0.04);
    display: flex;
    align-items: center;
    gap: 8px;
  }

  .file-toolbar button {
    background: none;
    border: none;
    color: #aaa;
    cursor: pointer;
    font-size: 16px;
    padding: 4px 8px;
    border-radius: 4px;
    transition: all 0.15s;
  }

  .file-toolbar button:hover { background: rgba(255,255,255,0.08); color: white; }

  #files-path {
    font-size: 13px;
    color: #bbb;
    flex: 1;
    min-width: 120px;
    background: rgba(0,0,0,0.25);
    padding: 4px 8px;
    border-radius: 4px;
    font-family: 'Ubuntu Mono', monospace;
  }

  #files-list {
    flex: 1;
    overflow-y: auto;
    padding: 8px 0;
  }

  .fs-item {
    display: flex;
    align-items: center;
    gap: 12px;
    padding: 6px 24px;
    cursor: pointer;
    color: #ddd;
    font-size: 14px;
    transition: background 0.1s;
    user-select: none;
  }

  .fs-item:hover { background: rgba(255,255,255,0.06); }

  .fs-item .item-icon { font-size: 20px; width: 24px; text-align: center; flex-shrink: 0; }
  .fs-item .item-name { flex: 1; }
  .fs-folder { color: #7ec8e3; }

  /* Notepad styles */
  #notepad-window .win-body { display: flex; flex-direction: column; height: 100%; }

  #tabs {
    display: flex;
    background: #25253a;
    border-bottom: 1px solid rgba(255,255,255,0.04);
    overflow-x: auto;
    min-height: 36px;
  }

  .tab {
    padding: 6px 16px;
    font-size: 13px;
    color: #999;
    cursor: pointer;
    border-right: 1px solid rgba(255,255,255,0.04);
    white-space: nowrap;
    background: transparent;
    transition: all 0.1s;
    user-select: none;
    display: flex;
    align-items: center;
    gap: 6px;
  }

  .tab:hover { color: #ddd; background: rgba(255,255,255,0.04); }
  .tab.active { color: white; background: #3a3a58; border-bottom: 2px solid #7ec8e3; }

  .tab-close-btn {
    width: 16px;
    height: 16px;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 10px;
    color: #777;
    cursor: pointer;
    transition: all 0.1s;
    line-height: 1;
  }

  .tab-close-btn:hover { background: #e95757; color: white; }

  #new-tab {
    padding: 6px 12px;
    font-size: 13px;
    color: #888;
    cursor: pointer;
    border-left: 1px solid rgba(255,255,255,0.04);
    background: transparent;
    transition: all 0.1s;
    user-select: none;
    display: flex;
    align-items: center;
    gap: 4px;
  }

  #new-tab:hover { color: white; background: rgba(255,255,255,0.06); }

  #editor {
    flex: 1;
    width: 100%;
    border: none;
    outline: none;
    resize: none;
    padding: 12px;
    font-family: 'Ubuntu Mono', 'Courier New', monospace;
    font-size: 14px;
    line-height: 1.6;
    background: #1e1e30;
    color: #d8d8e8;
    tab-size: 2;
  }

  /* Scrollbar */
  ::-webkit-scrollbar { width: 8px; height: 8px; }
  ::-webkit-scrollbar-track { background: transparent; }
  ::-webkit-scrollbar-thumb { background: #4a4a6a; border-radius: 4px; }
  ::-webkit-scrollbar-thumb:hover { background: #5a5a7a; }

  /* Dragging indicator */
  .window.dragging { opacity: 0.85; transition: none; }

  /* Hidden utility */
  .hidden { display: none !important; }
</style>
</head>
<body>

<div id="desktop">
  <!-- Desktop icons -->
  <div class="desktop-icon" onclick="openFiles()">
    <div class="icon-preview" style="background:#2d5a27;">📁</div>
    <div class="icon-label">Home</div>
  </div>

  <!-- Files Window -->
  <div id="files-window" class="window">
    <div class="win-titlebar" id="files-drag-handle">
      <span class="win-title">📁 File Manager</span>
      <button class="win-close" onclick="closeWindow('files-window')">✕</button>
    </div>
    <div class="win-body">
      <div class="file-toolbar">
        <button id="files-up" title="Go to parent directory" onclick="navigateUp()">⬆ Up</button>
        <span id="files-path">/</span>
      </div>
      <div id="files-list"></div>
    </div>
  </div>

  <!-- Notepad Window -->
  <div id="notepad-window" class="window">
    <div class="win-titlebar" id="notepad-drag-handle">
      <span class="win-title">📝 Text Editor</span>
      <button class="win-close" onclick="closeWindow('notepad-window')">✕</button>
    </div>
    <div class="win-body">
      <div id="tabs"></div>
      <textarea id="editor" placeholder="Start typing..."></textarea>
    </div>
  </div>
</div>

<div id="taskbar">
  <button id="open-files" onclick="openFiles()">
    <span class="icon">📁</span> Files
  </button>
  <button id="open-notepad" onclick="openNotepad()">
    <span class="icon">📝</span> Notepad
  </button>
  <div class="spacer"></div>
</div>

<script>
// ======================== FILESYSTEM DATA ========================
const fs = {
  '/': [
    { name: 'bin', type: 'folder' },
    { name: 'etc', type: 'folder' },
    { name: 'home', type: 'folder' },
    { name: 'usr', type: 'folder' },
    { name: 'var', type: 'folder' }
  ],
  '/bin': [
    { name: 'bash', type: 'file' },
    { name: 'ls', type: 'file' },
    { name: 'cp', type: 'file' },
    { name: 'mv', type: 'file' },
    { name: 'rm', type: 'file' }
  ],
  '/etc': [
    { name: 'passwd', type: 'file' },
    { name: 'hosts', type: 'file' },
    { name: 'ssh_config', type: 'file' }
  ],
  '/home': [
    { name: 'user', type: 'folder' }
  ],
  '/usr': [
    { name: 'bin', type: 'folder' },
    { name: 'lib', type: 'folder' },
    { name: 'share', type: 'folder' }
  ],
  '/var': [
    { name: 'log', type: 'folder' },
    { name: 'cache', type: 'folder' }
  ],
  '/home/user': [
    { name: 'Documents', type: 'folder' },
    { name: 'Downloads', type: 'folder' },
    { name: 'Pictures', type: 'folder' },
    { name: 'notes.txt', type: 'file' }
  ],
  '/home/user/Documents': [
    { name: 'todo.md', type: 'file' },
    { name: 'project-plan.docx', type: 'file' }
  ],
  '/home/user/Downloads': [
    { name: 'report.pdf', type: 'file' },
    { name: 'image.png', type: 'file' }
  ],
  '/home/user/Pictures': [
    { name: 'sunset.jpg', type: 'file' },
    { name: 'vacation.zip', type: 'file' }
  ]
};

// ======================== WINDOW MANAGEMENT ========================
let zIndexCounter = 100;

function bringToFront(id) {
  const win = document.getElementById(id);
  if (win) {
    zIndexCounter++;
    win.style.zIndex = zIndexCounter;
  }
}

function openWindow(id) {
  const win = document.getElementById(id);
  if (!win) return;
  win.classList.remove('hidden');
  bringToFront(id);
}

function closeWindow(id) {
  const win = document.getElementById(id);
  if (win) {
    win.style.display = 'none';
  }
}

// ======================== FILES APP ========================
let currentPath = '/';
const filesListEl = document.getElementById('files-list');
const filesPathEl = document.getElementById('files-path');

function renderFiles() {
  const entries = fs[currentPath] || [];
  filesListEl.innerHTML = '';

  if (entries.length === 0) {
    filesListEl.innerHTML = '<div class="fs-item" style="color:#666;">Empty directory</div>';
    return;
  }

  entries.forEach(entry => {
    const item = document.createElement('div');
    item.className = 'fs-item';
    if (entry.type === 'folder') {
      item.innerHTML = `<span class="item-icon fs-folder">📁</span><span class="item-name">${entry.name}</span>`;
    } else {
      item.innerHTML = `<span class="item-icon">📄</span><span class="item-name">${entry.name}</span>`;
    }

    if (entry.type === 'folder') {
      item.addEventListener('dblclick', () => navigateInto(entry.name));
    } else {
      item.addEventListener('dblclick', () => alert(`Opening ${entry.name}...`));
    }

    filesListEl.appendChild(item);
  });
}

function navigateInto(name) {
  const newPath = currentPath === '/' ? `/${name}` : `${currentPath}/${name}`;
  if (fs[newPath]) {
    currentPath = newPath;
    filesPathEl.textContent = currentPath;
    renderFiles();
    bringToFront('files-window');
  }
}

function navigateUp() {
  const parts = currentPath.split('/').filter(Boolean);
  if (parts.length > 1) {
    parts.pop();
    currentPath = '/' + parts.join('/');
    filesPathEl.textContent = currentPath;
    renderFiles();
    bringToFront('files-window');
  }
}

function openFiles() {
  closeWindow('files-window');
  setTimeout(() => {
    currentPath = '/';
    filesPathEl.textContent = '/';
    renderFiles();
    openWindow('files-window');
  }, 10);
}

// ======================== NOTEPAD APP ========================
const tabsData = []; // Array of tab objects: { id, title, content }
let activeTabId = null;
let nextTabId = 1;

function initNotepad() {
  const saved = localStorage.getItem('notepad_tabs');
  if (saved) {
    try {
      tabsData.length = 0;
      let idCounter = 1;
      for (const tab of JSON.parse(saved)) {
        tabsData.push({ ...tab, id: `tab-${idCounter++}` });
      }
      nextTabId = idCounter;
    } catch(e) {}
  }

  renderTabs();
}

function saveNotepad() {
  localStorage.setItem('notepad_tabs', JSON.stringify(tabsData));
}

function createTab(title, content = '') {
  const tabId = `tab-${nextTabId++}`;
  tabsData.push({ id: tabId, title: title || 'Untitled', content });
  renderTabs();
  switchToTab(tabId);
  saveNotepad();
}

function removeTab(tabId) {
  const idx = tabsData.findIndex(t => t.id === tabId);
  if (idx === -1) return;

  // If removing active, switch to another or create new
  if (activeTabId === tabId && tabsData.length > 1) {
    const nextIdx = Math.min(idx + 1, tabsData.length - 1);
    switchToTab(tabsData[nextIdx].id);
  } else if (activeTabId === tabId && tabsData.length === 1) {
    createTab('Untitled');
  }

  tabsData.splice(idx, 1);
  renderTabs();
  saveNotepad();
}

function switchToTab(tabId) {
  activeTabId = tabId;
  const editor = document.getElementById('editor');
  const tab = tabsData.find(t => t.id === tabId);
  if (tab) {
    editor.value = tab.content;
  } else {
    editor.value = '';
  }
  renderTabs();
}

function renderTabs() {
  const tabsEl = document.getElementById('tabs');
  tabsEl.innerHTML = '';

  tabsData.forEach(tab => {
    const tabEl = document.createElement('div');
    tabEl.className = `tab ${activeTabId === tab.id ? 'active' : ''}`;
    tabEl.dataset.tabId = tab.id;
    tabEl.innerHTML = `<span>${tab.title}</span><span class="tab-close-btn" onclick="removeTab('${tab.id}')">✕</span>`;

    tabEl.addEventListener('click', (e) => {
      if (!e.target.classList.contains('tab-close-btn')) {
        switchToTab(tab.id);
      }
    });

    tabsEl.appendChild(tabEl);
  });

  // Add new tab button
  const newBtn = document.createElement('div');
  newBtn.id = 'new-tab';
  newBtn.innerHTML = '<span>+</span> New Tab';
  newBtn.addEventListener('click', () => createTab());
  tabsEl.appendChild(newBtn);
}

function openNotepad() {
  closeWindow('notepad-window');
  setTimeout(() => {
    if (tabsData.length === 0) {
      createTab('Untitled');
    } else {
      switchToTab(tabsData[0].id);
    }
    openWindow('notepad-window');
  }, 10);
}

// ======================== DRAG FUNCTIONALITY ========================
function makeDraggable(handleId, winId) {
  const handle = document.getElementById(handleId);
  if (!handle || !document.getElementById(winId)) return;

  let isDragging = false;
  let startX, startY, startLeft, startTop;

  handle.addEventListener('mousedown', (e) => {
    bringToFront(winId);
    isDragging = true;
    document.body.classList.add('dragging');
    const win = document.getElementById(winId);
    startX = e.clientX;
    startY = e.clientY;
    startLeft = win.offsetLeft;
    startTop = win.offsetTop;

    // Calculate offset from top-left of window
    const rect = handle.getBoundingClientRect();
    const winRect = win.getBoundingClientRect();
    const offsetX = startX - rect.left;
    const offsetY = startY - rect.top;

    document.addEventListener('mousemove', onDrag);
    document.addEventListener('mouseup', stopDrag);
  });

  function onDrag(e) {
    if (!isDragging) return;
    e.preventDefault();
    const win = document.getElementById(winId);
    let newLeft = startLeft + (e.clientX - startX);
    let newTop = startTop + (e.clientY - startY);

    // Keep within viewport bounds
    const desktopH = document.getElementById('desktop').offsetHeight;
    const taskbarH = 48;
    const winW = win.offsetWidth;
    const winH = win.offsetHeight;

    newLeft = Math.max(0, Math.min(newLeft, window.innerWidth - winW));
    newTop = Math.max(0, Math.min(newTop, desktopH - taskbarH - winH));

    win.style.left = newLeft + 'px';
    win.style.top = newTop + 'px';
  }

  function stopDrag() {
    isDragging = false;
    document.body.classList.remove('dragging');
    document.removeEventListener('mousemove', onDrag);
    document.removeEventListener('mouseup', stopDrag);
  }
}

// ======================== INITIALIZATION ========================
document.addEventListener('DOMContentLoaded', () => {
  // Initialize notepad persistence
  initNotepad();

  // Make windows draggable
  makeDraggable('files-drag-handle', 'files-window');
  makeDraggable('notepad-drag-handle', 'notepad-window');

  // Initial render of files
  currentPath = '/';
  filesPathEl.textContent = '/';
  renderFiles();
});
</script>
</body>
</html>
